from pathlib import Path
from collections import OrderedDict
p=Path('/app/sequences.fasta').read_text().strip().splitlines()
seqs=OrderedDict(); name=None; parts=[]
for line in p:
    if line.startswith('>'):
        if name: seqs[name]=''.join(parts).strip().lower()
        name=line[1:].strip(); parts=[]
    else:
        parts.append(line.strip())
if name: seqs[name]=''.join(parts).strip().lower()
input_seq=seqs['input']; egfp=seqs['egfp']; flag=seqs['flag']; snap=seqs['snap']; out=seqs['output']
for name,seq in [('egfp',egfp),('flag',flag),('snap',snap)]:
    best=(0,None,None)
    # find longest substring of seq in out
    for i in range(len(seq)):
        for j in range(i+1+best[0], len(seq)+1):
            sub=seq[i:j]
            idx=out.find(sub)
            if idx!=-1:
                best=(j-i,i,idx)
    print(name,'bestlen',best[0],'seq_start',best[1],'out_idx',best[2])
